VALUES
  ('real-estate-moex-00978', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關契約之敘述，下列何者正確？', '["契約為事實行為的一種", "契約得因要約交錯之方式成立", "契約皆須以書面方式為之，方得以成立", "基於契約自由原則，醫生得拒絕醫治病情危急的情敵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00979', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依現行民法規定，有關違反法定要式規定之法律行為效力，下列何者應為無效？', '["會員已交付首期會款，但未訂立會單", "不動產買賣之債權契約，未經書面公證", "不動產租賃契約期限約定2年，且未以書面簽訂", "人事保證契約未以書面簽訂"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00980', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關不當得利所應返還之客體，下列何者錯誤？', '["原物所生之孳息", "受領之原物或原權利", "原物因受領人特殊能力導致之增值", "原物毀損後，受益時之價額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00981', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲欲向乙租屋3年，雙方僅用通訊軟體Line互相協商，乙已於對話中允諾，但後來丙出更高租金，於是 乙改將該屋出租給丙並交付之，後來丙得乙之同意將該屋再出租給丁，某日丁因大意未關爐火將該屋燒 毀，下列敘述何者正確？', '["乙可以向丁主張侵權行為責任", "甲可主張乙丙之租賃契約未以書面簽訂，因此無效", "丙可以向丁主張侵權行為責任", "甲可以向丙主張有優先締約權，因此乙丙之租賃契約對甲係屬無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00982', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依侵權行為請求損害賠償之說明，下列敘述何者正確？', '["純粹經濟上之損失亦屬於一種損害，與權利受損一樣，得依民法第184條第1項前段主張之", "債權亦屬於一種財產權，被侵害時，祗得依民法第184條第1項前段主張，而不得依同條項後段主張之", "我國侵權行為之保護客體僅限於權利，未及於利益", "故意以背於善良風俗之方法加損害於他人之利益，受害人亦得依侵權行為主張之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00983', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關民法第 250 條規定之違約金類型有「損害賠償總額預定違約金」與「懲罰性違約金」兩種，下列敘 述何者正確？', '["「損害賠償總額預定違約金」，倘若債務人有債務不履行發生，惟債權人所受實際損害遠低於約定之 額度時，債權人即不得請求此一違約金金額", "「懲罰性違約金」，只要債務人有債務不履行發生時，即便債權人未因此而受損害，債權人仍得請求 此一違約金金額", "「損害賠償總額預定違約金」，債務人有債務不履行發生，導致債權人受損害時，債權人除此一違約 金外，亦得請求其他損害賠償金額", "「懲罰性違約金」，債務人有債務不履行發生，導致債權人受損害時，債權人除此一違約金外，不得 請求其他損害賠償金額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00984', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '若買賣標的物為特定物時，買受人不得請求下列那一種物的瑕疵擔保之法定效果？', '["減價", "解約", "損害賠償", "另行交付他物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00985', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將透天厝（不含基地）立約賣給乙後，尚未交付予乙前，即逢超級強烈颱風來襲，致透天厝完全倒塌。 下列敘述何者正確？', '["乙免給付價金予甲", "甲仍負有交屋之義務", "甲仍得請求乙支付價金", "乙得向甲主張侵權行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00986', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關贈與契約之敘述，下列何者正確？', '["贈與契約一旦成立後，贈與人不得任意撤銷之", "贈與契約為要式契約，因此必須作成贈與契約書", "贈與屬於恩惠行為，故成立贈與契約無須受贈人之同意", "因贈與契約為無償契約，故原則上贈與人不負瑕疵擔保責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00987', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依民法之規定，承租人因下列何種情形致失火而使租賃物毀損、滅失者，應對出租人負損害賠償責任？', '["重大過失", "不可抗力", "具體輕過失", "抽象輕過失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00988', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關物權之優先性，在同一標的物下，下列敘述何者正確？', '["當所有權與定限物權併存時，所有權之效力依舊優先於定限物權", "當內容或性質相衝突之物權併存時，二者效力均等", "先成立用益物權，再設定擔保物權時，該擔保物權不得對抗該已成立之用益物權", "先成立擔保物權，再設定用益物權時，該擔保物權人無論如何皆可主張塗銷該用益物權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00989', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '民法第 796 條規定，土地所有人建築房屋非因故意或重大過失逾越地界者，鄰地所有人如知其越界而不 即提出異議，不得請求移去或變更其房屋。假設甲僅有抽象輕過失，且乙知其越界未即提出異議，下列 敘述何者正確？', '["甲將自己之㕑廁建於鄰地所有人乙之部分土地上，甲可以主張㕑廁亦屬於該條之「建築房屋」，不得拆除", "甲將房屋之全部建築在鄰地所有人乙之土地上，甲可以主張此符合「越界建築」之規定，不得拆除", "甲之立體停車場越界建築在鄰地所有人乙之土地上，則鄰地所有人乙，可以主張停車場並非是該條之「建築 房屋」而請求拆除", "甲所建房屋整體之外，越界加建房屋，則鄰地所有人乙，可以請求拆除該加建之房屋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00990', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關地上權之敘述，下列何者正確？', '["地上權乃為債權", "地上權人必須支付地租", "地上權之存續期間，有法定最長20年之限制", "地上權人原則上得將其權利讓與他人或設定抵押權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00991', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '民法規定，區分地上權人得與其設定之土地上下有使用、收益權利之人，約定相互間使用收益之限制。 其約定未經土地所有人同意者，於使用收益權消滅時，土地所有人不受該約定之拘束。此之「其設定之 土地上下有使用、收益權利之人」不包含下列何種？', '["普通地上權人", "不動產役權人", "農育權人", "典權人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00992', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '以他人不動產供自己不動產通行、汲水、採光、眺望、電信或以其他特定便宜之用者，稱為：', '["農育權", "抵押權", "不動產役權", "土地租賃權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00993', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關抵押權之特性，下列敘述何者錯誤？', '["當不動產所有人設定抵押權後，其抵押權不因該不動產之物權讓與而受影響", "抵押之不動產如經分割，其抵押權不因該不動產經分割或讓與一部而受影響", "以抵押權擔保之債權，其抵押權不因該債權經分割或讓與一部而受影響", "抵押權之獨立性在於其得由債權分離而為讓與，或為其他債權之擔保"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
